// Fungsi memuat produk ke halaman berdasarkan kategori sub-menu
function renderProducts(category) {
    const container = document.getElementById("product-container");
    container.innerHTML = ""; // Bersihkan isi lama

    const produkList = databaseProduk[category];
    
    produkList.forEach(produk => {
        const card = document.createElement("div");
        card.className = "product-card";
        
        card.innerHTML = `
            <img src="${produk.img}" alt="${produk.nama}">
            <div class="product-info">
                <h3>${produk.nama}</h3>
                <p class="desc">${produk.desc}</p>
                <p class="price">${produk.harga}</p>
                <button class="buy-btn" onclick="buyProduct('${produk.nama}')">Buy Now</button>
            </div>
        `;
        container.appendChild(card);
    });
}

// Fungsi ketika sub-menu diklik
function changeCategory(category) {
    let title = document.getElementById("page-title");
    
    // Ubah Judul Halaman Utama berdasarkan kategori sub-menu
    let formatTitle = category.charAt(0).toUpperCase() + category.slice(1);
    title.innerText = "Kategori Menu: " + (formatTitle === 'Kopi' ? 'Kopi & Teh' : formatTitle === 'Segar' ? 'Jus Segar' : formatTitle === 'Kue' ? 'Kue & Pastry' : formatTitle);
    
    // Tampilkan 6 produk baru milik sub-menu tersebut
    renderProducts(category);
}

// Saat pertama kali website dibuka, langsung tampilkan kategori tradisional secara otomatis
window.onload = function() {
    renderProducts("tradisional");
};

// Fungsi untuk Tombol Buy Now
function buyProduct(productName) {
    alert(`Terima kasih! Produk "${productName}" telah ditambahkan ke keranjang belanja.`);
}

// Fungsi Modal Register Pop-up
function openModal() {
    document.getElementById("registerModal").style.display = "flex";
}

function closeModal() {
    document.getElementById("registerModal").style.display = "none";
}

// Fungsi submit form pendaftaran
function submitRegister(event) {
    event.preventDefault();
    alert("Pendaftaran Berhasil! Selamat bergabung di Dapur Rasa.");
    closeModal();
}

// Menutup modal jika user klik di luar kotak modal
window.onclick = function(event) {
    let modal = document.getElementById("registerModal");
    if (event.target == modal) {
        modal.style.display = "none";
    }
}